1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const ITEM_BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	};
9	
10	type Item = { type: string };
11	type QuoteStep = { op: "quote"; items: Item[] };
12	type Step = QuoteStep;
13	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
14	
15	const itemBase = (item: Item): number => ITEM_BASE_PREMIUM[item.type];
16	
17	const quotePremium = (items: Item[]): number => {
18	  const basePremium = items.reduce((sum, item) => sum + itemBase(item), 0);
19	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
20	  return Math.ceil(basePremium + firstInsuranceSurcharge) + PROCESSING_FEE;
21	};
22	
23	export const runScenario = (scenario: Scenario): unknown => {
24	  const results = scenario.steps.map((step) => ({
25	    premium: quotePremium(step.items),
26	  }));
27	  return { results };
28	};
